            /* Verde do brasão de Santa Clara */
            --verde:       #2e7d32;
            --verde-light: #66bb6a;
            --verde-dim:   rgba(46,125,50,0.10);

            /* Azul das flores do linho (brasão) */
            --azul:        #5b8fc9;
            --azul-light:  #90b8e0;
            --azul-dim:    rgba(91,143,201,0.12);

            /* Dourado/terra dos campos */
            --dourado:     #c8922a;
            --dourado-light:#e8c070;
            --dourado-dim: rgba(200,146,42,0.12);

            /* Rosa suave para flores */
            --rosa:        #c06080;
            --rosa-light:  #dca0b8;
            --rosa-dim:    rgba(192,96,128,0.10);

            --border:      rgba(46,125,50,0.15);
            --border2:     rgba(46,125,50,0.07);

            --text:        #1a2e1a;
            --text-muted:  #5a7a5a;
