        .nota-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 12px;
        }

        .nota-title { font-size: 14px; font-weight: 500; color: var(--text); }

        .nota-range {
            font-size: 12px;
