            padding: 3px 10px;
            border-radius: 99px;
            border: 1px solid var(--border);
        }

        /* ══════════════════════════════════
           ANOTAÇÕES
        ══════════════════════════════════ */
        .annotation-area {
            background: var(--surface);
            border: 1px solid var(--border);
            border-radius: var(--radius);
            padding: 20px;
            height: 100%;
            display: flex;
            flex-direction: column;
            box-shadow: var(--shadow-card);
        }

        .annotation-area h3 {
            font-family: 'Cormorant Garamond', serif;
            font-size: 18px;
            font-weight: 600;
            font-style: italic;
            color: var(--text);
            margin-bottom: 14px;
        }

        .annotation-area textarea {
            flex: 1;
            width: 100%;
            min-height: 260px;
            background: var(--surface2);
            border: 1px solid var(--border);
            border-radius: var(--radius-sm);
            color: var(--text);
