            font-size: 14px;
            padding: 14px;
            resize: vertical;
            transition: border-color 0.2s;
        }

        .annotation-area textarea:focus {
            outline: none;
            border-color: var(--azul);
            box-shadow: 0 0 0 3px var(--azul-dim);
        }

        .annotation-area textarea::placeholder { color: var(--text-dim); }

        /* ══════════════════════════════════
           LAYOUT AVALIAÇÃO
        ══════════════════════════════════ */
        .eval-layout {
            display: grid;
            grid-template-columns: 1fr 2fr;
            gap: 28px;
        }

        @media (max-width: 900px) {
            .eval-layout { grid-template-columns: 1fr; }
            .annotation-area textarea { min-height: 120px; }
            .topbar { padding: 0 16px; }
            .topbar-brand-sub { display: none; }
            .container { padding: 24px 16px; }
        }

        /* ══════════════════════════════════
           TABELA ADMIN
        ══════════════════════════════════ */
        .table-wrapper {
            overflow-x: auto;
            border-radius: var(--radius);
            border: 1px solid var(--border);
            box-shadow: var(--shadow-card);
        }

        table {
            width: 100%;
            border-collapse: collapse;
            font-size: 14px;
            background: var(--surface);
        }

        thead tr { background: var(--surface2); }

        th {
            padding: 14px 20px;
            text-align: left;
            font-size: 11px;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 0.08em;
            color: var(--text-muted);
            white-space: nowrap;
        }

        tbody tr {
            border-top: 1px solid var(--border2);
            transition: background 0.15s;
        }

        tbody tr:hover { background: var(--verde-dim); }
        td { padding: 14px 20px; color: var(--text); }

        .rank-badge {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            width: 28px; height: 28px;
            border-radius: 50%;
            font-size: 12px;
            font-weight: 700;
        }

        .rank-1     { background: rgba(200,146,42,0.15);  color: var(--dourado); border: 1px solid var(--dourado-light); }
        .rank-2     { background: rgba(160,160,160,0.15); color: #888;           border: 1px solid #ccc; }
        .rank-3     { background: rgba(192,96,128,0.12);  color: var(--rosa);    border: 1px solid var(--rosa-light); }
        .rank-other { background: var(--surface2);        color: var(--text-dim);border: 1px solid var(--border); }

        .media-badge {
            font-family: 'Cormorant Garamond', serif;
            font-size: 20px;
            font-weight: 600;
            color: var(--verde);
        }

        .progress-wrap {
            background: var(--surface2);
            border-radius: 99px;
            height: 6px;
            overflow: hidden;
            width: 100px;
            border: 1px solid var(--border);
        }

        .progress-fill {
            height: 100%;
            background: linear-gradient(90deg, var(--verde), var(--verde-light));
            border-radius: 99px;
        }

        /* ══════════════════════════════════
           ALERTAS
        ══════════════════════════════════ */
        .alert { padding: 12px 16px; border-radius: var(--radius-sm); font-size: 14px; margin-bottom: 20px; }
        .alert-error   { background: rgba(192,57,43,0.07); border: 1px solid rgba(192,57,43,0.25); color: var(--red); }
        .alert-success { background: rgba(46,125,50,0.08); border: 1px solid rgba(46,125,50,0.3);  color: var(--green); }

        /* ══════════════════════════════════
           LOGIN
        ══════════════════════════════════ */
        .login-wrapper {
            min-height: 100vh;
